 2→export const PANEL_ID = `${ADDON_ID}/panel`;
 3→
 4→export const EVENTS = {
 5→  UPDATE_JSON: `${ADDON_ID}/update-json`,
 6→  SET_DEFAULT_JSON: `${ADDON_ID}/set-default-json`,
 7→  REQUEST_DEFAULT: `${ADDON_ID}/request-default`,
 8→} as const;
